{
  "title": "人工智能发展简史",
  "chapters": [
    {
      "title": "引言：AI的定义与历史脉络",
      "pages": [
        {
          "title": "什么是人工智能？",
          "bullets": [
            "AI是使机器模拟人类感知、学习、推理、决策和行动能力的科学与技术",
            "核心目标：构建能执行通常需人类智能的任务的系统",
            "区别于自动化：强调适应性、泛化性与自主性"
          ],
          "notes": "开场提问：‘你日常使用的哪些工具已嵌入AI？’ 引导学生联想手机语音助手、推荐系统等；过渡到‘这些能力并非一蹴而就，而是历经七十余年演进’"
        },
        {
          "title": "历史分期概览",
          "bullets": [
            "萌芽期（1950s–1960s）：概念诞生与符号主义奠基",
            "寒冬期（1970s）：期望落差与资金退潮",
            "专家系统时代（1980s）：知识工程商业化尝试",
            "机器学习崛起（1990s）：统计方法取代规则驱动",
            "深度学习爆发（2010s）：算力+数据+算法三重突破",
            "大模型时代（2020s至今）：生成式AI重塑人机交互"
          ],
          "notes": "用时间轴图示呈现六阶段；强调‘繁荣—寒冬—再突破’的螺旋式发展规律；为后续各章铺垫逻辑框架"
        }
      ]
    },
    {
      "title": "奠基与挫折：1950s–1970s",
      "pages": [
        {
          "title": "萌芽：从图灵测试到达特茅斯会议",
          "bullets": [
            "1950年图灵提出‘模仿游戏’（图灵测试），确立智能行为评判标准",
            "1956年达特茅斯会议首次使用‘Artificial Intelligence’术语，AI正式立科",
            "早期代表性程序：逻辑理论家（1956）、通用问题求解器GPS（1957）、感知机（1958）"
          ],
          "notes": "展示图灵论文手稿图片；点明‘达特茅斯’是AI的‘出生证明’；过渡：‘但兴奋很快遭遇现实冷水’"
        },
        {
          "title": "第一次AI寒冬（1970s）",
          "bullets": [
            "MYCIN（医疗诊断）与DENDRAL（化学分析）验证专家系统可行性",
            "1973年莱特希尔报告严厉质疑AI进展，称其‘未兑现通用智能承诺’",
            "英美政府大幅削减资助，学术信心受挫，研究转入低潮"
          ],
          "notes": "举例：MYCIN准确率超人类专家，却因无法解释推理过程难获临床信任；强调‘可解释性’问题早在1970年代已浮现"
        }
      ]
    },
    {
      "title": "知识驱动与商业落地：1980s",
      "pages": [
        {
          "title": "专家系统的黄金十年",
          "bullets": [
            "核心思想：将人类专家经验编码为‘if-then’规则库",
            "日本第五代计算机计划（1982）聚焦逻辑编程与并行推理",
            "美国MCC联盟推动知识工程标准化，XCON系统为DEC年省4000万美元"
          ],
          "notes": "对比XCON与传统人工配置流程：耗时从数小时降至秒级；提问：‘规则系统为何难以复制到金融或教育领域？’引出迁移瓶颈"
        },
        {
          "title": "局限与再次退潮",
          "bullets": [
            "知识获取瓶颈：依赖专家持续输入，成本高、易过时",
            "脆弱性：规则覆盖不全时系统完全失效，缺乏容错与学习能力",
            "1987年LISP机器市场崩溃，叠加日本项目未达预期，资金再度撤离"
          ],
          "notes": "类比‘Excel宏’——强大但难维护；小结：‘AI需要从‘知识搬运’走向‘知识生成’’"
        }
      ]
    },
    {
      "title": "范式转移：1990s–2000s",
      "pages": [
        {
          "title": "机器学习取代符号主义",
          "bullets": [
            "1995年SVM提出，奠定高维空间分类理论基础",
            "1997年深蓝击败卡斯帕罗夫，标志计算智能里程碑",
            "1997年随机森林问世，提升集成学习鲁棒性与可解释性"
          ],
          "notes": "播放深蓝对弈片段（3秒）；强调‘深蓝非学习型AI，而是暴力搜索+人工调优’，反衬后续学习范式的革命性"
        },
        {
          "title": "数据与统计方法的崛起",
          "bullets": [
            "互联网兴起带来海量标注数据（如Reuters新闻语料库）",
            "贝叶斯网络、隐马尔可夫模型（HMM）支撑语音识别初步商用",
            "‘数据即新石油’理念初现，算法重心从‘设计规则’转向‘拟合分布’"
          ],
          "notes": "举例：早期语音助手错误率＞30%，依赖HMM建模声学特征；过渡：‘但数据量与算力仍制约模型复杂度’"
        }
      ]
    },
    {
      "title": "深度革命：2010s",
      "pages": [
        {
          "title": "AlexNet引爆神经网络复兴",
          "bullets": [
            "2012年AlexNet以15.3%错误率碾压传统方法（26.2%），GPU训练首秀成功",
            "关键创新：ReLU激活函数、Dropout正则、数据增强缓解过拟合",
            "开启CV领域‘卷积网络主导时代’，产业界加速布局AI芯片"
          ],
          "notes": "展示ImageNet分类样例图；说明‘GPU并行计算使百万参数训练成为可能’；点明‘工程突破常先于理论突破’"
        },
        {
          "title": "从感知到博弈：AlphaGo里程碑",
          "bullets": [
            "2016年AlphaGo融合蒙特卡洛树搜索（MCTS）与深度神经网络",
            "围棋状态空间10^170，远超宇宙原子数（10^80），证明AI可攻克‘直觉型’任务",
            "策略网络+价值网络双架构，实现自我对弈强化学习"
          ],
          "notes": "播放李世石落子后AlphaGo长考画面；强调‘这不是暴力穷举，而是类人模式识别与规划’"
        },
        {
          "title": "NLP的结构化跃迁",
          "bullets": [
            "2014年Seq2Seq+Attention解决变长序列映射（如机器翻译）",
            "2017年Transformer摒弃RNN，实现并行训练与长程依赖建模",
            "2018年BERT（双向预训练）与GPT（单向生成）奠定大模型双路径"
          ],
          "notes": "用‘翻译句子’对比RNN逐词处理 vs Transformer全局注意力；小结：‘架构创新为大模型铺平道路’"
        }
      ]
    },
    {
      "title": "生成式AI时代：2020s至今",
      "pages": [
        {
          "title": "ChatGPT：现象级产品引爆点",
          "bullets": [
            "2022年11月ChatGPT发布，5天破百万用户，2个月月活破亿",
            "基于GPT-3.5微调，首次让大众直观体验‘对话式通用AI’",
            "界面极简（聊天框）、能力惊艳（写诗/编码/推理），重塑人机交互范式"
          ],
          "notes": "展示ChatGPT早期用户增长曲线；提问：‘为什么这次AI热潮比以往更持久？’引出‘可用性’与‘普惠性’突破"
        },
        {
          "title": "全球大模型生态竞速",
          "bullets": [
            "OpenAI GPT-4（2023）：多模态理解、复杂推理、考试成绩超人类",
            "中国主力模型：文心一言（百度）、通义千问（阿里）、ChatGLM（智谱）、DeepSeek（深度求索）",
            "2025趋势：开源模型（如Qwen、DeepSeek-V2）性能逼近闭源，降低应用门槛"
          ],
          "notes": "对比GPT-4与GLM-4在MMLU基准得分（86.4 vs 83.2）；强调‘中国模型在中文理解、代码生成等场景具本地优势’"
        },
        {
          "title": "AI能力边界拓展",
          "bullets": [
            "从‘感知智能’（看/听/说）迈向‘决策智能’（规划/执行/反思）",
            "AI Agent兴起：AutoGen、LangChain支持多Agent协作完成端到端任务",
            "具身智能探索：机器人+大模型实现物理世界交互（如Figure 01）"
          ],
          "notes": "演示AutoGen自动订会议室+发通知流程；指出‘Agent不是新模型，而是新架构范式’"
        }
      ]
    },
    {
      "title": "挑战与未来：走向可信AI",
      "pages": [
        {
          "title": "当前核心挑战",
          "bullets": [
            "幻觉（Hallucination）：生成看似合理但事实错误的内容",
            "算力与能耗：训练GPT-3碳排放≈5辆汽车终身排放，绿色AI成刚需",
            "数据版权与隐私：训练数据权属不清，合成内容监管缺位"
          ],
          "notes": "举例：AI生成‘某教授发表于Nature的不存在论文’；强调‘工程课需关注技术负外部性’"
        },
        {
          "title": "前沿探索方向",
          "bullets": [
            "高效小模型：TinyBERT、Phi-3适配边缘设备（手机/IoT）",
            "可解释AI（XAI）：注意力可视化、归因分析提升决策可信度",
            "AI对齐（Alignment）：RLHF、Constitutional AI确保价值观一致性"
          ],
          "notes": "对比手机端运行Phi-3（1.5B）vs 云端调用GPT-4（1.7T）延迟与成本；结语：‘下一代AI工程师，既要懂模型，更要懂约束’"
        }
      ]
    }
  ]
}
